  const [isDeleting, setIsDeleting] = useState(false);

  // Count-up metrics
  const [metric1, setMetric1] = useState(0);
  const [metric2, setMetric2] = useState(0);
  const [metric3, setMetric3] = useState(0);
  const [metric4, setMetric4] = useState(0.0);

