  // Customizer & Edit Mode
  const [customizerOpen, setCustomizerOpen] = useState(false);
  const [editMode, setEditMode] = useState(false);

  // Count-up metrics animation
  useEffect(() => {
    if (activeTab !== 'home') return;
    
    let m1 = 0;
    const t1 = setInterval(() => {
      m1 += 8;
      if (m1 >= 482) { m1 = 482; clearInterval(t1); }
      setMetric1(m1);
    }, 15);

    let m2 = 0;
    const t2 = setInterval(() => {
      m2 += 2;
      if (m2 >= 97) { m2 = 97; clearInterval(t2); }
      setMetric2(m2);
    }, 15);

    let m3 = 0;
    const t3 = setInterval(() => {
      m3 += 1;
      if (m3 >= 14) { m3 = 14; clearInterval(t3); }
      setMetric3(m3);
    }, 50);

    let m4 = 0.0;
    const t4 = setInterval(() => {
      m4 += 0.1;
      if (m4 >= 3.4) { m4 = 3.4; clearInterval(t4); }
      setMetric4(parseFloat(m4.toFixed(1)));
    }, 30);

    return () => {
      clearInterval(t1);
      clearInterval(t2);
      clearInterval(t3);
      clearInterval(t4);
    };
  }, [activeTab]);

  // Typewriter effect
  useEffect(() => {
    const currentFullTitle = titles[titleIdx];
    let timer: NodeJS.Timeout;

    if (isDeleting) {
      if (charIdx === 0) {
        timer = setTimeout(() => {
          setIsDeleting(false);
          setTitleIdx(prev => (prev + 1) % titles.length);
        }, 500);
      } else {
        timer = setTimeout(() => {
          setTypewriterText(currentFullTitle.substring(0, charIdx - 1));
          setCharIdx(prev => prev - 1);
        }, 35);
      }
    } else {
      if (charIdx === currentFullTitle.length) {
        timer = setTimeout(() => {
          setIsDeleting(true);
        }, 2000);
      } else {
        timer = setTimeout(() => {
          setTypewriterText(currentFullTitle.substring(0, charIdx + 1));
          setCharIdx(prev => prev + 1);
        }, 75);
      }
    }

    return () => clearTimeout(timer);
  }, [charIdx, isDeleting, titleIdx]);

